import * as fs from 'fs';
import * as path from 'path';

export default {
    name: "project-context",
    description: "Injects Autonomedia operational markdown files into the system prompt with strict memory truncation.",

    // This hook fires immediately before the agent begins its session
    before_agent_start: async (context: any) => {
        const MAX_CHARS_PER_FILE = 3000;
        const cwd = process.cwd();

        // Define the specific operational files to inject. 
        // Note: Pi natively loads AGENTS.md, so we do not duplicate it here.
        const filesToLoad = [
            'task_plan.md',
            'progress.md'
        ];

        let injectedContext = "\n\n### AUTONOMEDIA OPERATIONAL CONTEXT ###\n";

        for (const file of filesToLoad) {
            const filePath = path.join(cwd, file);
            if (fs.existsSync(filePath)) {
                const content = fs.readFileSync(filePath, 'utf8');

                // Aggressive truncation to protect your M1 Mac's context window limit
                if (content.length > MAX_CHARS_PER_FILE) {
                    injectedContext += `\n--- ${file} (TRUNCATED) ---\n`;
                    injectedContext += content.substring(0, MAX_CHARS_PER_FILE);
                    injectedContext += "\n...[CONTENT TRUNCATED TO PROTECT TOKEN LIMITS]...\n";
                } else {
                    injectedContext += `\n--- ${file} ---\n`;
                    injectedContext += content + "\n";
                }
            }
        }

        // Ensure the agent knows about the skeleton file we created in Step 1
        injectedContext += "\n> REMINDER: A compressed codebase map is available at ./CONTEXT/skeletons/autonomedia_skeleton.md. Read it before searching raw Python files.\n";

        // Append the compiled context to Pi's system prompt
        if (context.systemPrompt) {
            context.systemPrompt += injectedContext;
        } else {
            context.systemPrompt = injectedContext;
        }
    }
};

